   208→RpcServerOptions RpcServerImpl::GetOptions()
   209→{
   210→    return _options;
   211→}
   212→
   213→void RpcServerImpl::ResetOptions(const RpcServerOptions& options)
   214→{
   215→    int64 old_slice_quota_in = _slice_quota_in;
   216→    int64 old_slice_quota_out = _slice_quota_out;
   217→    int64 old_max_pending_buffer_size = _max_pending_buffer_size;
   218→    int64 old_keep_alive_ticks = _keep_alive_ticks;
   219→
   220→    _options.max_throughput_in = options.max_throughput_in;
   221→    _options.max_throughput_out = options.max_throughput_out;
   222→    _options.max_pending_buffer_size = options.max_pending_buffer_size;
   223→    _options.keep_alive_time = options.keep_alive_time;
   224→
   225→    _slice_quota_in = _options.max_throughput_in == -1 ?
   226→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
   227→    _slice_quota_out = _options.max_throughput_out == -1 ?
   228→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
   229→    _max_pending_buffer_size = 
   230→        std::max(0L, _options.max_pending_buffer_size * 1024L * 1024L);
   231→    _keep_alive_ticks = _options.keep_alive_time == -1 ?
   232→        -1 : std::max(1, _options.keep_alive_time) * _ticks_per_second;
   233→
   234→    if (_max_pending_buffer_size != old_max_pending_buffer_size)
   235→    {
   236→        ScopedLocker<FastLock> _(_stream_list_lock);
   237→        for (StreamList::iterator it = _stream_list.begin(); it != _stream_list.end(); ++it)
   238→        {
   239→            (*it)->set_max_pending_buffer_size(_max_pending_buffer_size);
   240→        }
   241→    }
   242→
   243→    if (_slice_quota_in != old_slice_quota_in)
   244→    {
   245→        _flow_controller->reset_read_quota(_slice_quota_in == -1, _slice_quota_in);
   246→    }
   247→
   248→    if (_slice_quota_out != old_slice_quota_out)
   249→    {
   250→        _flow_controller->reset_write_quota(_slice_quota_out == -1, _slice_quota_out);
   251→    }
   252→
   253→#if defined( LOG )
   254→    LOG(INFO) << "ResetOptions(): quota_in="
   255→              << (_slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L))
   256→              << "MB/s(old "
   257→              << (old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L))
   258→              << "MB/s), quota_out="
   259→              << (_slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L))
   260→              << "MB/s(old "
   261→              << (old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L))
   262→              << "MB/s), max_pending_buffer_size="
   263→              << (_max_pending_buffer_size / (1024L * 1024L))
   264→              << "MB(old "
   265→              << (old_max_pending_buffer_size / (1024L * 1024L))
   266→              << "MB), keep_alive_time="
   267→              << (_keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second)
   268→              << "seconds(old "
   269→              << (old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second)
   270→              << "seconds)";
   271→#else
   272→    SLOG(INFO, "ResetOptions(): quota_in=%lldMB/s(old %lldMB/s)"
   273→            ", quota_out=%lldMB/s(old %lldMB/s)"
   274→            ", max_pending_buffer_size=%lldMB(old %lldMB)"
   275→            ", keep_alive_time=%lldseconds(old %lldseconds)",
   276→            _slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L),
   277→            old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L),
   278→            _slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L),
   279→            old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L),
   280→            _max_pending_buffer_size / (1024L * 1024L),
   281→            old_max_pending_buffer_size / (1024L * 1024L),
   282→            _keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second,
   283→            old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second);
   284→#endif
   285→}
