   302→
   303→void RpcServerImpl::GetPendingStat(int64* pending_message_count,
   304→        int64* pending_buffer_size, int64* pending_data_size)
   305→{
   306→    ScopedLocker<FastLock> _(_stream_list_lock);
   307→    int64 message_count = 0;
   308→    int64 buffer_size = 0;
   309→    int64 data_size = 0;
   310→    for (StreamList::iterator it = _stream_list.begin();
   311→            it != _stream_list.end(); ++it)
   312→    {
   313→        message_count += (*it)->pending_message_count();
   314→        buffer_size += (*it)->pending_buffer_size();
   315→        data_size += (*it)->pending_data_size();
   316→    }
   317→    *pending_message_count = message_count;
   318→    *pending_buffer_size = buffer_size;
   319→    *pending_data_size = data_size;
   320→}
   321→
   322→bool RpcServerImpl::IsListening()
   323→{
   324→    ScopedLocker<MutexLock> _(_start_stop_lock);
   325→    return _is_running && !_listener->is_closed();
   326→}
   327→
   328→bool RpcServerImpl::RestartListen()
   329→{
   330→    ScopedLocker<MutexLock> _(_start_stop_lock);
   331→    if (!_is_running)
   332→    {
   333→#if defined( LOG )
   334→        LOG(ERROR) << "RestartListen(): server not in running";
   335→#else
   336→        SLOG(ERROR, "RestartListen(): server not in running");
   337→#endif
   338→        return false;
   339→    }
   340→
   341→    // close listener first
   342→    _listener->close();
   343→
   344→    // reset and restart listener
   345→    _listener.reset(new RpcListener(_work_thread_group->io_service(), _listen_endpoint));
   346→    _listener->set_create_callback(boost::bind(
   347→                &RpcServerImpl::OnCreated, shared_from_this(), _1));
   348→    _listener->set_accept_callback(boost::bind(
   349→                &RpcServerImpl::OnAccepted, shared_from_this(), _1));
   350→    _listener->set_accept_fail_callback(boost::bind(
   351→                &RpcServerImpl::OnAcceptFailed, shared_from_this(), _1, _2));
   352→    if (!_listener->start_listen())
   353→    {
   354→#if defined( LOG )
   355→        LOG(ERROR) << "RestartListen(): listen failed: " << _server_address;
   356→#else
   357→        SLOG(ERROR, "RestartListen(): listen failed: %s", _server_address.c_str());
   358→#endif
   359→        return false;
   360→    }
   361→
   362→#if defined( LOG )
   363→    LOG(INFO) << "RestartListen(): restart listener succeed";
   364→#else
   365→    SLOG(INFO, "RestartListen(): restart listener succeed");
   366→#endif
   367→    return true;
   368→}
   369→
   370→void RpcServerImpl::OnCreated(const RpcServerStreamPtr& stream)
   371→{
   372→    stream->set_flow_controller(_flow_controller);
   373→    stream->set_received_request_callback(
   374→            boost::bind(&RpcServerImpl::OnReceived, shared_from_this(), _1, _2));
   375→}
   376→
   377→void RpcServerImpl::OnAccepted(const RpcServerStreamPtr& stream)
   378→{
   379→    if (!_is_running)
   380→    {
   381→        stream->close("server not running");
   382→        return;
   383→    }
   384→
   385→    stream->set_max_pending_buffer_size(_max_pending_buffer_size);
   386→    stream->reset_ticks((ptime_now() - _start_time).ticks(), true);
   387→
   388→    ScopedLocker<FastLock> _(_stream_list_lock);
   389→    _stream_list.push_back(stream);
   390→}
   391→
   392→void RpcServerImpl::OnAcceptFailed(RpcErrorCode error_code, const std::string& error_text)
   393→{
   394→    if (!_is_running)
   395→        return;
   396→
   397→    // callback
   398→    if (_event_handler)
   399→    {
   400→        _event_handler->NotifyAcceptFailed(error_code, error_text);
   401→    }
   402→}
   403→
   404→void RpcServerImpl::OnReceived(const RpcServerStreamWPtr& stream, const RpcRequestPtr& request)
   405→{
   406→    if (!_is_running)
   407→    {
   408→#if defined( LOG )
   409→        LOG(ERROR) << "OnReceived(): " << RpcEndpointToString(request->RemoteEndpoint())
   410→                   << ": server not in running, ignore";
   411→#else
   412→        SLOG(ERROR, "OnReceived(): %s: server not in running, ignore",
   413→                RpcEndpointToString(request->RemoteEndpoint()).c_str());
   414→#endif
   415→        return;
   416→    }
   417→
   418→    request->ProcessRequest(stream, _service_pool);
   419→}
   420→
   421→void RpcServerImpl::StopStreams()
   422→{
   423→    ScopedLocker<FastLock> _(_stream_list_lock);
   424→    for (StreamList::iterator it = _stream_list.begin();
   425→            it != _stream_list.end(); ++it)
   426→    {
   427→        (*it)->close("server stopped");
   428→    }
   429→}
   430→
   431→void RpcServerImpl::ClearStreams()
   432→{
   433→    ScopedLocker<FastLock> _(_stream_list_lock);
   434→    _stream_list.clear();
   435→}
   436→
   437→void RpcServerImpl::TimerMaintain(const PTime& now)
   438→{
   439→    SOFA_PBRPC_FUNCTION_TRACE;
   440→
   441→    int64 now_ticks = (now - _start_time).ticks();
   442→
   443→    // check listener, if closed, then try to restart it every interval.
   444→    if (_listener->is_closed()
   445→            && now_ticks - _last_restart_listen_ticks >= _restart_listen_interval_ticks)
   446→    {
   447→        _last_restart_listen_ticks = now_ticks;
   448→        RestartListen();
   449→    }
   450→
   451→    // check streams, if closed, then remove from list
   452→    std::list<RpcServerStreamPtr> live_streams;
   453→    std::list<RpcServerStreamPtr> closed_streams;
   454→    int live_count = 0;
   455→    {
   456→        ScopedLocker<FastLock> _(_stream_list_lock);
   457→        for (StreamList::iterator it = _stream_list.begin();
   458→                it != _stream_list.end(); )
   459→        {
   460→            const RpcServerStreamPtr& stream = *it;
   461→
   462→            if (_keep_alive_ticks != -1
   463→                    && now_ticks - stream->last_rw_ticks() >= _keep_alive_ticks)
   464→            {
   465→                stream->close("keep alive timeout");
   466→            }
   467→
   468→            if (stream->is_closed())
   469→            {
   470→                closed_streams.push_back(stream);
   471→                it = _stream_list.erase(it);
   472→            }
   473→            else
   474→            {
   475→                stream->reset_ticks(now_ticks, false);
   476→                live_streams.push_back(stream);
   477→                ++live_count;
   478→                ++it;
   479→            }
   480→        }
   481→    }
   482→    _live_stream_count = live_count;
   483→
   484→    // flow control
   485→    if (_slice_quota_in != -1)
   486→    {
   487→        // reset quota pool
   488→        _flow_controller->reset_read_quota(_slice_quota_in);
   489→
   490→        // collect streams need to trigger
   491→        std::vector<FlowControlItem> trigger_list;
   492→        for (std::list<RpcServerStreamPtr>::iterator it = live_streams.begin();
   493→                it != live_streams.end(); ++it)
   494→        {
   495→            int token = (*it)->read_quota_token();
   496→            if (token <= 0)
   497→            {
   498→                // only need trigger streams whose token <= 0
   499→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   500→            }
   501→        }
   502→
   503→        // sort by token: token closer to zero, earlier to trigger
   504→        std::sort(trigger_list.begin(), trigger_list.end());
   505→
   506→        // trigger in order
   507→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   508→                t_it != trigger_list.end(); ++t_it)
   509→        {
   510→            t_it->stream->trigger_receive();
   511→        }
   512→    }
   513→    if (_slice_quota_out != -1)
   514→    {
   515→        // reset quota pool
   516→        _flow_controller->reset_write_quota(_slice_quota_out);
   517→
   518→        // collect streams need to trigger
   519→        std::vector<FlowControlItem> trigger_list;
   520→        for (std::list<RpcServerStreamPtr>::iterator it = live_streams.begin();
   521→                it != live_streams.end(); ++it)
   522→        {
   523→            int token = (*it)->write_quota_token();
   524→            if (token <= 0)
   525→            {
   526→                // only need trigger streams whose token <= 0
   527→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   528→            }
   529→        }
   530→
   531→        // sort by token: token closer to zero, earlier to trigger
   532→        std::sort(trigger_list.begin(), trigger_list.end());
   533→
   534→        // trigger in order
   535→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   536→                t_it != trigger_list.end(); ++t_it)
   537→        {
   538→            t_it->stream->trigger_send();
   539→        }
   540→    }
   541→
   542→    if (now_ticks - _last_switch_stat_slot_ticks >= _switch_stat_slot_interval_ticks)
   543→    {
   544→        _last_switch_stat_slot_ticks = now_ticks;
   545→        _service_pool->NextSlot();
   546→    }
   547→
   548→    if (now_ticks - _last_print_connection_ticks >= _print_connection_interval_ticks)
   549→    {
   550→        _last_print_connection_ticks = now_ticks;
   551→#if defined( LOG )
   552→        LOG(INFO) << "TimerMaintain(): countof(RpcListener)="
   553→                  << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener)
   554→                  << ", countof(RpcByteStream)=" << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream)
   555→                  << ", live_stream_count=" << _live_stream_count;
   556→#else
   557→        SLOG(INFO, "TimerMaintain(): countof(RpcListener)=%ld"
   558→                ", countof(RpcByteStream)=%ld, live_stream_count=%d",
   559→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener),
   560→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream),
   561→                _live_stream_count);
   562→#endif
   563→    }
   564→
   565→    _last_maintain_ticks = now_ticks;
   566→}
   567→
   568→} // namespace pbrpc
   569→} // namespace sofa
   570→
